    }"
    counter-key="@((string)context.Variables["tenant_id"])"
    estimate-prompt-tokens="true"
    tokens-consumed-header-name="X-Tokens-Consumed"
    remaining-tokens-header-name="X-RateLimit-Tokens-Remaining"
    retry-after-header-name="Retry-After" />







        application/json

      @{
        var tenantId = context.Variables.GetValueOrDefault("tenant_id") ?? "unknown";
        var tier = context.Variables.GetValueOrDefault("tenant_tier") ?? "standard";
        var retryAfter = context.Response.Headers.GetValueOrDefault("Retry-After", "60");
        return new JObject(
          new JProperty("error", "token_quota_exceeded"),
          new JProperty("tenant_id", tenantId),
          new JProperty("tier", tier),
          new JProperty("retry_after_seconds", int.Parse(retryAfter)),
          new JProperty("message", $"Token quota exceeded for tenant '{tenantId}' on tier '{tier}'. Tokens-per-minute window resets in {retryAfter}s.")
        ).ToString();
      }
